g.script:

 var geojson = (function () {
			var json = null;
			$.ajax({
					'async': false,
					'global': false,
					'url': 'dataset.json',
					'dataType': "json",
					'success': function (data) {
							json = data;
					}
			});
			return json;
	})();

	var query = window.location.search.substring(1);
	var vars = query.split("&amp;");
	var ward;

	for (var i=0;i<vars.length;i++) {
			var pair = vars[i].split("=");
			if (pair[0] == "ward") {
			ward = pair[1];
		}
	}

	String.prototype.replaceAll = function(target, replacement) {
		return this.split(target).join(replacement);
	};

	ward = ward.replaceAll("%20"," ");

	geojson.features.forEach(function(marker) {
			if(marker.properties.ward == ward)
			{
				$("#wardname").text(marker.properties.ward);
				$("#uniquevoters").text(marker.properties.voters.toString().concat(" voters"));
				$("#female").text(marker.properties.female);
				$("#male").text(marker.properties.male);
				$("#trans").text(((marker.properties.trans<10)&(marker.properties.trans>0))?("0".concat(marker.properties.trans.toString())):(marker.properties.trans));
				//Modify radii of the circles:
				$("#cmale").attr("r", marker.properties.male/1800);
				$("#cfemale").attr("r", marker.properties.female/1800);
				var transRadius = marker.properties.trans/1800;
				transRadius = (transRadius < 1) ? 2 : marker.properties.trans;
				$("#ctrans").attr("r", transRadius);

				$("#duplicatedEPIC").text(marker.properties.EPICdupl);
				$("#suspected").text(marker.properties.EPICmult);
				$("#original").text(marker.properties.original);
				$("#modified").text(marker.properties.modified);
				$("#repeated").text(marker.properties.repeated);
				$("#shifted").text(marker.properties.shifted);
				$("#expired").text(marker.properties.expired);
				$("#added").text(marker.properties.added);
				$("#disqualified").text(marker.properties.disqualified);

				//document.getElementById('plotly').innerHTML = "<object type=\"text/html\" data=\"Agegraph/plotly.html?ward="+ward+"\" width=\"540px\" height=\"400px\" style=\"overflow: hidden;margin-top:250px; margin-left:-40px;\"></object>";
				//console.log(document.getElementById('plotly').innerHTML);
			}
	});
